{
  "summary": "This paper introduces AmbiBench, a benchmark of ambiguously specified binary classification tasks to study task ambiguity distinct from input ambiguity. It empirically evaluates humans and various language models, showing that RLHF-trained models and finetuning on ambiguous examples improve ambiguity resolution, highlighting the importance of ambiguity-aware training.",
  "strengths": [
    {
      "point": "Novel problem formulation focusing on task ambiguity distinct from input ambiguity",
      "evidence": "The paper clearly motivates the need to study task ambiguity where the intended task itself is ambiguous given instructions and examples."
    },
    {
      "point": "Development of a controlled benchmark (AmbiBench) with templated sentences allowing precise ambiguity control",
      "evidence": "AmbiBench consists of six binary classification tasks with two competing linguistic features, enabling systematic study of ambiguity resolution."
    },
    {
      "point": "Comprehensive empirical evaluation comparing humans, RLHF-trained models, and non-RLHF models",
      "evidence": "Results show RLHF-trained models approach or exceed human performance, while others struggle, and finetuning on ambiguous examples closes the gap."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited novelty claim due to insufficient comparison with prior work on instruction ambiguity and prompt engineering",
      "evidence": "The paper does not thoroughly position itself against related literature on instruction ambiguity or few-shot learning ambiguity."
    },
    {
      "point": "Simplified methodology using only binary classification tasks with templated sentences",
      "evidence": "No justification is provided for restricting to binary tasks, and potential limitations of templated sentences for ecological validity are not discussed."
    },
    {
      "point": "Evaluation lacks inclusion of other strong instruction-tuned models and detailed finetuning setup",
      "evidence": "Comparison omits models like FLAN-T5; finetuning data size and diversity are unspecified, limiting assessment of scalability."
    },
    {
      "point": "Reproducibility concerns due to missing details on human experiments, prompt templates, and hyperparameters",
      "evidence": "Participant demographics, exact instructions, prompt examples, and inference hyperparameters are not provided."
    },
    {
      "point": "Limited analysis of robustness to prompt variations and ambiguity types beyond linguistic features",
      "evidence": "No systematic study of prompt sensitivity or coverage of other ambiguity types such as goal ambiguity or multimodal ambiguity."
    }
  ],
  "questions": [
    {
      "question": "How well do the findings generalize to more complex, multi-class, or multi-label ambiguous tasks?",
      "motivation": "Real-world task ambiguity often involves more complex settings than binary classification, affecting applicability."
    },
    {
      "question": "What specific aspects of RLHF training enable better ambiguity resolution compared to instruction tuning alone?",
      "motivation": "Understanding the mechanisms behind RLHF's advantage could guide improved training strategies."
    },
    {
      "question": "How sensitive are the results to prompt design and wording variations?",
      "motivation": "Prompt engineering is known to impact model behavior; robustness to such variations is critical for practical deployment."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
